def beautifulIndices(self, s: str, a: str, b: str, k: int) -> List[int]:
    result = []
    for i in range(len(s)):
        if s[i] == a and s[i+len(a)-1] == b and abs(i - (i + len(a) - 1)) <= k:
            result.append(i)
    return sorted(result)

